using System.Collections.Generic;
using UnityEngine;
using UnityEngine.Events;

/// <summary>
/// Plataforma móvel genérica, configurável inteiramente pelo Inspector
/// (sem precisar de sub-classes por tipo de plataforma).
///
/// ACTIVAÇÃO POR ALAVANCA: não existe (nem é preciso) um script especial de
/// "alavanca de plataforma". Usa-se o mesmo padrão já existente no projecto
/// (Lever/Switch → GameVariables): coloca uma Lever/Switch normal com
/// "variableName" = ex. "PlataformaSala02", e nesta plataforma define-se
/// "activacao = VariavelGlobal" e "activationVariable = PlataformaSala02".
/// Vantagem: a mesma alavanca pode ligar várias plataformas/portas/inimigos
/// ao mesmo tempo (todos a lerem a mesma variável), sem nenhuma referência
/// directa entre objectos — igual ao resto do jogo (portas, torretas, etc.).
///
/// TIPOS DE MOVIMENTO (tipoMovimento):
/// - Parada: não se desloca (útil só para "Cair ao Pisar").
/// - Linear: anda numa linha (Horizontal ou Vertical) por "distancia" a
///   partir da posição inicial. "vaiEVolta" = ping-pong (desligado = pára
///   definitivamente na extremidade — "pára nas extremidades").
/// - Circular: orbita num círculo de raio "raio" à volta da posição inicial.
/// - Percurso: segue uma lista de Transforms ("pontosDoPercurso") colocados
///   na cena — arrasta GameObjects vazios para o array no Inspector.
///
/// "Cair ao Pisar" e "Transporta o Player" funcionam com qualquer
/// tipoMovimento (incluindo "Parada").
/// </summary>
[RequireComponent(typeof(Rigidbody2D))]
[DisallowMultipleComponent]
public class MovingPlatform : MonoBehaviour
{
    public enum TipoMovimento { Parada, Linear, Circular, Percurso }
    public enum EixoLinear { Horizontal, Vertical }
    public enum ModoActivacao { Sempre, VariavelGlobal, AoPlayerPisar }

    [Header("Activação")]
    [Tooltip("Sempre = move-se desde o início. Variável Global = só se move enquanto a variável (escrita por uma Lever/Switch) for TRUE. Ao Player Pisar = só começa a mover-se depois do player pisar nela pela primeira vez.")]
    public ModoActivacao activacao = ModoActivacao.Sempre;

    [Tooltip("Nome da variável global (GameVariables) lida quando activacao = VariavelGlobal — usa o mesmo nome escrito por uma Lever/Switch existente.")]
    public string activationVariable = "";

    [Tooltip("Enquanto inactiva (variável false / ainda não pisada), a plataforma volta lentamente à posição inicial em vez de ficar parada onde está.")]
    public bool returnToStartWhenInactive = false;

    [Header("Tipo de Movimento")]
    public TipoMovimento tipoMovimento = TipoMovimento.Linear;

    [Tooltip("Velocidade de deslocação (unidades/segundo).")]
    [Min(0.01f)] public float speed = 2f;

    [Header("Linear (Horizontal / Vertical)")]
    public EixoLinear eixo = EixoLinear.Horizontal;

    [Tooltip("Distância total percorrida a partir da posição inicial.")]
    [Min(0f)] public float distancia = 3f;

    [Tooltip("Ligado: ao chegar à extremidade, volta (vai-e-volta). Desligado: a plataforma PÁRA definitivamente na extremidade.")]
    public bool vaiEVolta = true;

    [Tooltip("Tempo (segundos) parada em cada extremidade antes de voltar (só com 'vaiEVolta' ligado).")]
    [Min(0f)] public float pausaNasExtremidades = 0f;

    [Header("Circular")]
    [Min(0.01f)] public float raio = 2f;

    [Tooltip("Ligado = sentido horário. Desligado = anti-horário.")]
    public bool sentidoHorario = true;

    [Header("Percurso (Waypoints)")]
    [Tooltip("Pontos do percurso, na ordem (arrasta Transforms/GameObjects vazios colocados na cena).")]
    public Transform[] pontosDoPercurso;

    [Tooltip("Ligado: ao chegar ao último ponto salta para o primeiro (ciclo fechado). Desligado: vai-e-volta entre os pontos.")]
    public bool percursoEmLoop = true;

    [Header("Cair ao Pisar")]
    [Tooltip("A plataforma cai por gravidade depois do player a pisar.")]
    public bool caiAoPisar = false;

    [Tooltip("Tempo (segundos) depois do player pisar até a plataforma começar a cair.")]
    [Min(0f)] public float tempoAteCair = 0.5f;

    [Tooltip("Tempo (segundos) até a plataforma reaparecer na posição inicial depois de cair (0 = não reaparece).")]
    [Min(0f)] public float tempoReaparecer = 0f;

    [Header("Transporta o Player")]
    [Tooltip("Enquanto o player estiver em cima, é arrastado junto com a plataforma.")]
    public bool transportaPlayer = true;

    [Header("Eventos")]
    [Tooltip("Linear (chegou a uma extremidade) ou Percurso (chegou a um ponto).")]
    public UnityEvent onChegouAoFim;
    public UnityEvent onComecouACair;
    public UnityEvent onReapareceu;

    private Rigidbody2D _rb;
    private Collider2D _col;
    private Vector2 _startPos;

    // Circular
    private Vector2 _center;
    private float _angle;

    // Linear
    private float _linearT;
    private int _linearDir = 1;
    private bool _linearFinished;

    // Percurso
    private int _pathIndex;
    private int _pathDir = 1;

    // Pausa partilhada (linear/percurso)
    private float _pauseTimer;

    // Activação / cair ao pisar / transporte
    private bool _steppedOn;
    private bool _falling;
    private float _fallTimer;
    private readonly HashSet<Rigidbody2D> _occupants = new HashSet<Rigidbody2D>();

    private void Awake()
    {
        _rb = GetComponent<Rigidbody2D>();
        _col = GetComponent<Collider2D>();

        _rb.bodyType = RigidbodyType2D.Kinematic;
        _startPos = _rb.position;

        // O centro da órbita fica a "raio" de distância para a plataforma
        // começar exactamente onde foi colocada na cena (ângulo 0).
        _center = _startPos - new Vector2(raio, 0f);
    }

    private void FixedUpdate()
    {
        Vector2 oldPos = _rb.position;
        Vector2 newPos = oldPos;

        if (!_falling)
        {
            if (IsActive())
                newPos = ComputeNextPosition(oldPos);
            else if (returnToStartWhenInactive)
                newPos = Vector2.MoveTowards(oldPos, _startPos, speed * Time.fixedDeltaTime);

            if (newPos != oldPos)
                _rb.MovePosition(newPos);
        }

        // Arrasta quem estiver em cima pela mesma diferença que a plataforma andou.
        Vector2 delta = newPos - oldPos;
        if (transportaPlayer && !_falling && delta.sqrMagnitude > 0f)
        {
            foreach (var occupant in _occupants)
            {
                if (occupant == null) continue;
                occupant.position += delta;
            }
        }

        UpdateFallOnStep();
    }

    // ---------------- Activação ----------------

    private bool IsActive()
    {
        switch (activacao)
        {
            case ModoActivacao.VariavelGlobal:
                if (string.IsNullOrEmpty(activationVariable)) return true;
                return GameVariables.Instance != null && GameVariables.Instance.GetBool(activationVariable);

            case ModoActivacao.AoPlayerPisar:
                return _steppedOn;

            default: // Sempre
                return true;
        }
    }

    // ---------------- Movimento ----------------

    private Vector2 ComputeNextPosition(Vector2 currentPos)
    {
        switch (tipoMovimento)
        {
            case TipoMovimento.Linear: return ComputeLinear(currentPos);
            case TipoMovimento.Circular: return ComputeCircular();
            case TipoMovimento.Percurso: return ComputePath(currentPos);
            default: return currentPos; // Parada
        }
    }

    private Vector2 ComputeLinear(Vector2 currentPos)
    {
        if (_linearFinished) return currentPos;

        if (_pauseTimer > 0f)
        {
            _pauseTimer -= Time.fixedDeltaTime;
            return currentPos;
        }

        _linearT += speed * Time.fixedDeltaTime * _linearDir;

        if (_linearT >= distancia)
        {
            _linearT = distancia;
            ReachedLinearEnd();
        }
        else if (_linearT <= 0f)
        {
            _linearT = 0f;
            ReachedLinearEnd();
        }

        Vector2 dir = eixo == EixoLinear.Horizontal ? Vector2.right : Vector2.up;
        return _startPos + dir * _linearT;
    }

    private void ReachedLinearEnd()
    {
        onChegouAoFim?.Invoke();

        if (!vaiEVolta)
        {
            _linearFinished = true;
            return;
        }

        _linearDir *= -1;
        if (pausaNasExtremidades > 0f)
            _pauseTimer = pausaNasExtremidades;
    }

    private Vector2 ComputeCircular()
    {
        // velocidade angular (rad/s) tal que a velocidade linear ao longo da
        // circunferência seja "speed".
        float angularSpeed = speed / Mathf.Max(0.01f, raio);
        _angle += angularSpeed * Time.fixedDeltaTime * (sentidoHorario ? -1f : 1f);

        return _center + new Vector2(Mathf.Cos(_angle), Mathf.Sin(_angle)) * raio;
    }

    private Vector2 ComputePath(Vector2 currentPos)
    {
        if (pontosDoPercurso == null || pontosDoPercurso.Length == 0) return currentPos;
        if (pontosDoPercurso.Length == 1) return pontosDoPercurso[0] != null ? (Vector2)pontosDoPercurso[0].position : currentPos;

        if (_pauseTimer > 0f)
        {
            _pauseTimer -= Time.fixedDeltaTime;
            return currentPos;
        }

        var targetT = pontosDoPercurso[_pathIndex];
        if (targetT == null) return currentPos;

        Vector2 target = targetT.position;
        Vector2 newPos = Vector2.MoveTowards(currentPos, target, speed * Time.fixedDeltaTime);

        if (newPos == target)
            AdvancePathIndex();

        return newPos;
    }

    private void AdvancePathIndex()
    {
        onChegouAoFim?.Invoke();

        int last = pontosDoPercurso.Length - 1;

        if (percursoEmLoop)
        {
            _pathIndex = (_pathIndex + 1) % pontosDoPercurso.Length;
            return;
        }

        // Vai-e-volta: chegou a uma ponta -> pausa (opcional) e inverte sentido.
        if (_pathIndex == last && _pathDir == 1)
        {
            if (pausaNasExtremidades > 0f) _pauseTimer = pausaNasExtremidades;
            _pathDir = -1;
        }
        else if (_pathIndex == 0 && _pathDir == -1)
        {
            if (pausaNasExtremidades > 0f) _pauseTimer = pausaNasExtremidades;
            _pathDir = 1;
        }

        _pathIndex += _pathDir;
    }

    // ---------------- Player em cima (pisar / transportar / cair) ----------------

    private void OnCollisionEnter2D(Collision2D collision) => UpdateOccupant(collision, true);
    private void OnCollisionStay2D(Collision2D collision) => UpdateOccupant(collision, true);
    private void OnCollisionExit2D(Collision2D collision) => UpdateOccupant(collision, false);

    private void UpdateOccupant(Collision2D collision, bool entering)
    {
        if (!collision.collider.CompareTag("Player")) return;

        if (!entering)
        {
            if (collision.rigidbody != null) _occupants.Remove(collision.rigidbody);
            return;
        }

        if (!IsOnTop(collision.collider)) return;

        _steppedOn = true;

        if (transportaPlayer && collision.rigidbody != null)
            _occupants.Add(collision.rigidbody);
    }

    /// <summary>true se a base de "other" estiver acima do topo da plataforma (pisando-a, não a tocar de lado/baixo).</summary>
    private bool IsOnTop(Collider2D other)
    {
        if (_col == null) return true;
        return other.bounds.min.y >= _col.bounds.max.y - 0.15f;
    }

    private void UpdateFallOnStep()
    {
        if (!caiAoPisar || _falling || !_steppedOn) return;

        _fallTimer += Time.fixedDeltaTime;
        if (_fallTimer >= tempoAteCair)
            StartFalling();
    }

    private void StartFalling()
    {
        _falling = true;
        _occupants.Clear();

        _rb.bodyType = RigidbodyType2D.Dynamic;
        _rb.linearVelocity = Vector2.zero;

        onComecouACair?.Invoke();

        if (tempoReaparecer > 0f)
            Invoke(nameof(Respawn), tempoReaparecer);
    }

    private void Respawn()
    {
        _falling = false;
        _steppedOn = false;
        _fallTimer = 0f;

        _linearFinished = false;
        _linearT = 0f;
        _linearDir = 1;
        _pathIndex = 0;
        _pathDir = 1;
        _angle = 0f;
        _pauseTimer = 0f;

        _rb.bodyType = RigidbodyType2D.Kinematic;
        _rb.linearVelocity = Vector2.zero;
        _rb.position = _startPos;

        onReapareceu?.Invoke();
    }

    // ---------------- Gizmos ----------------

    private void OnDrawGizmosSelected()
    {
        Vector2 pos = Application.isPlaying ? _startPos : (Vector2)transform.position;
        Gizmos.color = new Color(0.2f, 0.9f, 1f);

        switch (tipoMovimento)
        {
            case TipoMovimento.Linear:
                Vector2 dir = eixo == EixoLinear.Horizontal ? Vector2.right : Vector2.up;
                Gizmos.DrawLine(pos, pos + dir * distancia);
                Gizmos.DrawWireSphere(pos + dir * distancia, 0.15f);
                break;

            case TipoMovimento.Circular:
                Vector2 center = pos - new Vector2(raio, 0f);
                DrawGizmoCircle(center, raio);
                break;

            case TipoMovimento.Percurso:
                if (pontosDoPercurso == null) break;
                for (int i = 0; i < pontosDoPercurso.Length; i++)
                {
                    if (pontosDoPercurso[i] == null) continue;
                    Gizmos.DrawWireSphere(pontosDoPercurso[i].position, 0.15f);
                    if (i > 0 && pontosDoPercurso[i - 1] != null)
                        Gizmos.DrawLine(pontosDoPercurso[i - 1].position, pontosDoPercurso[i].position);
                }
                if (percursoEmLoop && pontosDoPercurso.Length > 1
                    && pontosDoPercurso[0] != null && pontosDoPercurso[pontosDoPercurso.Length - 1] != null)
                {
                    Gizmos.DrawLine(pontosDoPercurso[pontosDoPercurso.Length - 1].position, pontosDoPercurso[0].position);
                }
                break;
        }
    }

    private static void DrawGizmoCircle(Vector2 center, float radius)
    {
        const int segments = 32;
        Vector2 prev = center + new Vector2(radius, 0f);
        for (int i = 1; i <= segments; i++)
        {
            float a = i / (float)segments * Mathf.PI * 2f;
            Vector2 next = center + new Vector2(Mathf.Cos(a), Mathf.Sin(a)) * radius;
            Gizmos.DrawLine(prev, next);
            prev = next;
        }
    }
}
